import React, { useState, useEffect } from "react";

function ComplaintForm({ onSubmit, existingData, onCancel }) {
  const [complaint, setComplaint] = useState({
    clientName: "",
    designerId: "",
    description: "",
    date: ""
  });

  useEffect(() => {
    if (existingData) setComplaint(existingData);
  }, [existingData]);

  const handleChange = (e) => {
    setComplaint({ ...complaint, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    onSubmit(complaint);
  };

  // Set min date to today
  const today = new Date().toISOString().split("T")[0]; // format YYYY-MM-DD

  return (
    <div className="form-overlay">
      <form className="form-container" onSubmit={handleSubmit}>
        <h3>{existingData ? "Edit Complaint" : "Add Complaint"}</h3>

        <input
          type="text"
          name="clientName"
          placeholder="Client Name"
          value={complaint.clientName}
          onChange={handleChange}
          required
        />

        <input
          type="text"
          name="designerId"
          placeholder="Designer ID"
          value={complaint.designerId}
          onChange={handleChange}
          required
        />

        <textarea
          name="description"
          placeholder="Description"
          value={complaint.description}
          onChange={handleChange}
          required
        />

        <input
          type="date"
          name="date"
          value={complaint.date}
          onChange={handleChange}
          min={today} // <-- restrict past dates
          required
        />

        <div style={{ textAlign: "center" }}>
          <button type="submit">{existingData ? "Update" : "Add"}</button>
          <button type="button" className="cancel-btn" onClick={onCancel}>
            Cancel
          </button>
        </div>
      </form>
    </div>
  );
}

export default ComplaintForm;
